/**
 * Advanced User Validation & Deduplication
 * Logic: Checks (Email -> Name -> Gender) to flag invalid/duplicate users.
 */

const items = $input.all();
if (items.length === 0) return [];

// 1. Identify the 'Recent' item (the newest entry from the trigger)
// We assume the last item in the array is the new incoming data
const recent = items[items.length - 1].json;

const recentEmail  = (recent.Email || "").toLowerCase().trim();
const recentName   = (recent.Name || "").toLowerCase().trim();
const recentGender = (recent.Gender || "").toLowerCase().trim();

// 2. Scan all PREVIOUS items in the database for a triple-match
let isInvalidUser = false;

// We loop through all items except the very last one (which is our current input)
for (let i = 0; i < items.length - 1; i++) {
    const existing = items[i].json;

    const emailMatch  = (existing.Email || "").toLowerCase().trim() === recentEmail;
    const nameMatch   = (existing.Name || "").toLowerCase().trim() === recentName;
    const genderMatch = (existing.Gender || "").toLowerCase().trim() === recentGender;

    // Strict validation: All three must match to flag as invalid
    if (emailMatch && nameMatch && genderMatch) {
        isInvalidUser = true;
        break; 
    }
}

// 3. Construct Output with Status Flags
// This allows the next node (Filter/If) to decide the path
return [{
    json: {
        ...recent,
        validation_status: isInvalidUser ? "invalid user" : "valid user",
        response: "yes", // Hardcoded as requested
        timestamp: recent.Timestamp || new Date().toISOString(),
        duplicate_check: isInvalidUser ? "MATCH FOUND: Duplicate Identity" : "UNIQUE: New User"
    }
}];

