// 1. Define keywords (lowercase only)
const yesWords = ["yes","Yes" ,"YES" ,"yeah", "yup", "sure", "ok", "okay", "yess", "agree"];
const noWords = ["no", "nope","NO" ,"No" ,"not", "never", "nah"];

const results = [];

for (const item of $input.all()) {
  // 2. Clean and Lowercase the text
  // This ensures "YES!!!" becomes "yes" and handles paragraphs
  const rawSnippet = item.json.snippet || "";
  const cleanText = rawSnippet.toLowerCase().replace(/[^a-z\s]/g, " ");

  // 3. WHOLE WORD MATCHING: Split into a Set for exact matches only
  // This prevents "Yesterday" from triggering "yes"
  const wordsInSnippet = new Set(cleanText.split(/\s+/));

  let response = null;
  const hasYes = yesWords.some(word => wordsInSnippet.has(word));
  const hasNo = noWords.some(word => wordsInSnippet.has(word));

  // 4. CONFLICT HANDLING
  if (hasYes && !hasNo) {
    response = "yes";
  } else if (hasNo && !hasYes) {
    response = "no";
  } else if (hasYes && hasNo) {
    // If paragraph contains both "yes" and "no", label as mixed
    response = "mixed/check-manual";
  }

  // 5. GMAIL FIELD FIX: Dig into headers if 'From' is missing
  let senderEmail = item.json.From; 
  if (!senderEmail && item.json.payload?.headers) {
    const fromHeader = item.json.payload.headers.find(h => h.name === 'From');
    senderEmail = fromHeader ? fromHeader.value : "Unknown";
  }

  if (response) {
    results.push({
      json: {
        response: response,
        emailId: item.json.threadId || item.json.id,
        senderEmail: senderEmail,
        snippetPreview: rawSnippet.substring(0, 50) + "..."
      }
    });
  }
}

return results;

