    }
  };
});

/**
 * Advanced Name & Title Formatter (Safe Version)
 */

return $input.all().map(item => {
    const json = item.json;

    // 1. Base name fallback
    let baseName = json.extractedName || json.Name || "Customer";
    baseName = baseName.trim();

    // 2. Normalize gender
    const gender = (json.Gender || "").toLowerCase().trim();

    // 3. Decide title ONLY for male/female
    let title = "";
    if (gender === "male") {
        title = "Mr.";
    } else if (gender === "female") {
        title = "Ms.";
    }

    // 4. Remove any existing title first (defensive cleanup)
    const cleanedName = baseName.replace(/^(mr\.?|ms\.?|mrs\.?)/i, "").trim();

    // 5. Final logic
    let finalName = cleanedName;
    if (title) {
        finalName = `${title} ${cleanedName}`;
    }
    // If gender not male/female → just cleanedName

    return {
        json: {
