/**
 * Advanced Entity Extraction Node
 * Logic: Extracts clean names and emails from complex headers and snippets.
 */

// 1. Process all incoming items
return $input.all().map(item => {
    const json = item.json;

    // --- STEP 1: Identify the source string ---
    // We check 'senderEmail' (from your previous node) or the raw 'From' field
    let rawSender = json.senderEmail || json.From || "";

    // Fallback: If From is hidden in payload headers (Gmail standard)
    if (!rawSender && json.payload?.headers) {
        const fromHeader = json.payload.headers.find(h => h.name === 'From');
        rawSender = fromHeader ? fromHeader.value : "";
    }

    // --- STEP 2: Extraction Logic ---
    let cleanName = "Unknown";
    let cleanEmail = "Unknown";

    if (rawSender.includes("<")) {
        // Pattern matches: Name <email@domain.com>
        const match = rawSender.match(/^(.*?)\s*<(.*?)>$/);
        if (match) {
            // Remove quotes if the name is "John Doe"
            cleanName = match[1].replace(/['"]/g, "").trim();
            cleanEmail = match[2].trim();
        }
    } else if (rawSender.includes("@")) {
        // If it's just an email, use the part before @ as the name
        cleanEmail = rawSender.trim();
        cleanName = cleanEmail.split("@")[0];
    }

    // --- STEP 3: Snippet Context ---
    const snippet = json.snippet || json.snippetPreview || "";

    // Return the high-level structured object
    return {
        json: {
            extractedName: cleanName,
            extractedEmail: cleanEmail,
            originalResponse: json.response || "not detected",
            emailId: json.emailId || json.id,
            processedAt: new Date().toISOString()
        }
    };
});

